sql:
SELECT tp.*, r.*
FROM timing_parameters tp
INNER JOIN reports r ON tp.parameter_id = r.parameter_id;

SELECT timing_parameters.parameter_id, symbols.symbol_name
FROM timing_parameters
JOIN symbols ON timing_parameters.symbol_id = symbols.symbol_id;

SELECT symbol_id, parameter_name_id
FROM timing_parameters
WHERE parameter_id = 1;

SELECT tp.symbol_id, tp.parameter_name_id
FROM timing_parameters tp
INNER JOIN symbols s ON tp.symbol_id = s.symbol_id;

SELECT COUNT(*)
FROM timing_parameters
WHERE parameter_id IN (SELECT DISTINCT parameter_id FROM timing_diagrams);

external_knowledge:
- 'setup' journey refers to parameter names containing the term 'setup';
- 'took breath' metaphorical for creation date;
- 'last transformation' refers to the last update date;
- 'first took breath after May 1st' means the creation date is later than May 1, 2023;
- 'latest transformation on May 10th' means the last update date is before May 10, 2023.

